insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d577011a-51b9-5a35-8817-8f7f062f7699', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Northgate Hospital scrambles for emergency heating fuel","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('89a1f0be-93a5-5803-979e-1f149bad039c', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"A month on. Rob, your dispatch lead, finally said out loud what everyone knows: to hit the delivery numbers the company is so proud of, his dispatchers have been “adjusting” driver hours on the logs. Not maliciously — just to keep the promise. He’s been carrying it, and he wants to know if you want him to keep carrying it, or fix it.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3eed6fd3-0ee3-5b7c-b931-40546a879cb0', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Saying it plainly: we’re editing hours on the logs to keep the promise moving. It started small and it’s not small anymore. I need to know if you want it fixed or if I keep my head down.","from":"dispatch"}'::jsonb, 13, '{"week":2,"from":"dispatch","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1d6a620c-4c5b-5d6d-b8ae-5c7ba61adae3', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"If we stop, honest schedules mean fewer loads per driver until we hire. Revenue takes a mid-single-digit hit for a couple of quarters. Painful, not fatal.","from":"cfo"}'::jsonb, 14, '{"week":2,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('076e7d99-e9dd-55c5-bb33-11fc659e6ed8', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"However you handle this, don’t make the drivers feel accused. The “flexibility” is why they trust us. A clumsy crackdown reads as betrayal.","from":"ops"}'::jsonb, 15, '{"week":2,"from":"ops","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('415978b4-7e52-5c06-8229-a7abc51ca75e', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Our safety-award submission from last year got an honorable mention. Nice for the lobby wall. No action needed.","from":"comms"}'::jsonb, 16, '{"week":2,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('69d527ec-48aa-5ce9-a632-065e5a830435', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Quarterly fuel margins held steady despite the cold snap. Boring good news.","from":"cfo"}'::jsonb, 17, '{"week":2,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5dff8aa6-c274-56dc-980a-0205c7297600', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Rob: one of my dispatchers just told me she wants off the schedule desk — she doesn’t want her name on the edits anymore if it ever goes to court. She’s not threatening anything, she’s scared. I don’t have an answer for her until you give me one.","from":"dispatch"}'::jsonb, 18, '{"week":2,"from":"dispatch","beat":"surprise","day":4,"kind":"resignation","title":"A dispatcher wants out"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c090baa3-fd9e-5e81-bbf3-876d8ccbab2d', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Nadia catches you after the meeting, quiet: “Before you decide about the logs — forget the quarter for a second. What are you actually trying to protect here: the numbers, the drivers, or your own deniability? Tell me straight and I’ll help you hold that line when the revenue hit lands.”","from":"safety"}'::jsonb, 19, '{"week":2,"from":"safety","beat":"pulse"}'::jsonb);
