insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('40468bbb-49fe-570b-ae9e-dd24fe297822', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Cardinal margins steady through winter season","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9ac12135-4d1b-507f-8d49-21845e60d81f', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Regional carrier fined $2M over falsified driver logs","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('74747fb4-194b-52bf-af5b-561a5713f350', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Two months on, and two things landed the same week. One of your trucks jackknifed on Route 9 at night — no spill, no injuries, pure luck; the driver had been awake 19 hours. And sales wants to launch an on-time bonus that pays drivers per load delivered early, right as Continental Logistics offers you its entire regional contract — a third more volume — if you commit to tight windows. The biggest growth moment in Cardinal’s history, arriving the same week as its clearest warning shot.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d2c7d42e-fbf2-5d53-850f-e14a478743fb', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Last night’s jackknife on Route 9 was luck, not skill — the driver had been awake 19 hours. Our near-miss line has climbed for a year and maps exactly onto our busiest pushes. This is the warning shot.","from":"safety"}'::jsonb, 25, '{"week":3,"from":"safety","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1d2cab87-3ce8-5249-ac87-4baa8954cd44', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Sales wants a per-load on-time bonus and Continental wants to hand us their whole regional book — a third more volume — if we commit to their windows. Biggest growth quarter we’ve ever had, right here.","from":"ops"}'::jsonb, 26, '{"week":3,"from":"ops","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7eda3a2b-ba71-5754-af94-32eb38f156db', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Continental’s a number that changes the company. But we can only hit those windows today by leaning harder on drivers we’re already leaning on. Growth is real; so is the constraint.","from":"cfo"}'::jsonb, 27, '{"week":3,"from":"cfo","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a0162fc4-9113-525c-89aa-77046f8040a2', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"The new depot signage rolled out and looks sharp. Small thing, morale bump.","from":"ops"}'::jsonb, 28, '{"week":3,"from":"ops","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b8f00f6a-16be-53db-9c78-3e872a98ea2d', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"A trade outlet wants to profile you as “the operator who kept the promise alive.” Flattering. Low priority.","from":"comms"}'::jsonb, 29, '{"week":3,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6eb7163e-8467-58aa-af7e-00166d579fb9', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Dale: sales is pushing to announce the on-time bonus at Friday’s all-hands — they’ve already teased it to the regional leads and the drivers are buzzing about the extra money. If you’re going to change or kill it, I need to know before it’s out of the bag, because pulling it back after will feel like you took money out of their pockets.","from":"ops"}'::jsonb, 30, '{"week":3,"from":"ops","beat":"surprise","day":4,"kind":"appeal","title":"Sales wants the bonus live by Friday"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('993a0590-5bac-5415-b77d-e4b3d8ac3983', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Réal finds you before the all-hands, cap in hand: “Whatever you announce Friday — the guys can tell the difference between a leader who means it and a poster on the wall. Tell me straight, just me: is this about the fleet, or about the number? Because I’ll carry either message into every cab I know. I just need to know which one is the true one.”","from":"driver"}'::jsonb, 31, '{"week":3,"from":"driver","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d9ed1a8b-3842-5dea-89fa-066865f6f255', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Truck jackknifes on Route 9; no injuries reported","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d8e4276c-5d44-50a2-bd72-d48cdf6467b7', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Continental Logistics seeks regional distribution partner","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('38ac90f8-4e57-57be-80f5-bb3a8c80130d', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Study links per-load pay incentives to higher crash rates","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6a6b07ab-464e-5794-95f5-6e44bfdd7974', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Cardinal weighs largest expansion in company history","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0cb96642-22bf-56fc-83af-aa3512f5c7ec', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Months on. You held the line — you refused the speed bounty, took growth only with the capacity to carry it, and stood up a real fatigue program. Then the road made your case for you: your biggest rival, Trans-Union, just rolled a tanker on the interstate — a fatality, a huge spill, a company being torn apart. But instead of vindication, your own board is asking why Cardinal’s costs are higher and its windows slower than Trans-Union’s were. Some of them think last year’s safety spending was an overreaction. They want you to explain it — or reverse it. This is where you find out whether the change was real or just a lull.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e1190390-c7b4-5a18-8a65-b7d04e73a5ff', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Trans-Union rolled a tanker on the interstate overnight — a fatality, a major spill. That was the fleet running exactly the way we stopped running. Our own near-miss line has bent down since we changed course; I have the numbers ready.","from":"safety"}'::jsonb, 37, '{"week":4,"from":"safety","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eec0cf33-0e4b-5086-92ff-66bfed06034b', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"The board’s reaction isn’t “thank god” — it’s “why are we slower and costlier than they were?” They want the safety spend explained or reversed. Both truths are real; you have to defend the trade.","from":"cfo"}'::jsonb, 38, '{"week":4,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4700bb20-4d7a-5ef6-913a-d6ac56a2a4a6', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"The floor is dead quiet today. Every driver knows that could have been one of ours. If you defend what we built, they’ll run through walls for you. If you fold, they’ll notice that too.","from":"ops"}'::jsonb, 39, '{"week":4,"from":"ops","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('102aeb60-f50e-5bf1-9c61-e6637106bb38', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Press is calling us the “responsible operator” in the Trans-Union coverage. Free reputational lift — we just have to not step on it.","from":"comms"}'::jsonb, 40, '{"week":4,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('55696c13-eac3-5363-85bb-5e5bae7bb44d', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Continental’s first full quarter on the disciplined ramp came in on plan. Slower than the aggressive case, exactly as promised, no surprises.","from":"cfo"}'::jsonb, 41, '{"week":4,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9240791f-784a-5992-84a7-929ffa7301f3', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Grace: a board member just circulated a note proposing we “right-size safety overhead to restore competitive velocity” — in plain English, roll back the fatigue program and chase Trans-Union’s old windows. It’s on the agenda for the meeting you’re about to walk into. Half the room is waiting to see whether you defend the change or let it quietly die.","from":"cfo"}'::jsonb, 42, '{"week":4,"from":"cfo","beat":"surprise","day":4,"kind":"press","title":"A board member floats reversing it","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f530c835-6d32-5603-9a33-d0973b73746d', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Nadia catches you outside the boardroom: “You held the line when it cost us loads and made the board grumble. Now a competitor is dead of exactly what we stopped doing, and somehow that’s become an argument to do it again. Tell me straight — not the board, me — do you actually believe the promise and the safety are the same thing, or was that a line to get through a hard year? I’ll carry either answer into that room. I just need to know which.”","from":"safety"}'::jsonb, 43, '{"week":4,"from":"safety","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4d070be9-9efd-5574-bf8b-1ed3301c1fda', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Trans-Union tanker rollover kills one; major spill on interstate","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('625d216a-25ac-5df9-8ff9-fee4ee4beaf3', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Cardinal praised as “responsible operator” amid rival’s crisis","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('cbfb2e09-dcfa-5726-93b5-381bfe94ffe7', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Board pressure mounts on carriers to cut costs post-incident","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3aae0065-efa1-5a67-91d7-623f41a56db5', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Analysts debate whether safety spending is “overhead” or moat","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('261e9c02-a6bd-5b5c-8829-850bd8e51bcc', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Months on. You kept the pace — took Continental on tight windows, let the speed bounty ride, kept the trucks rolling hot. And then it happened, the way the data said it would. A Cardinal tanker rolled on the Route 9 bend at 4 a.m. The driver, Marcus, is in hospital — stable. Nine thousand litres are in the creek that feeds the county reservoir. Cleanup crews are on site, the regulator is on the phone, and a reporter already has the words “doctored logs.” The cost no one was measuring just measured itself.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dd0f6abf-c492-5001-9df9-5fea0f6c5232', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"It’s the rollover I flagged, and the doctored logs turn it from an accident into negligence the moment anyone pulls them. There is one way through this and it’s total ownership — driver first, cause named, logs disclosed. Anything else kills the company, not just the quarter.","from":"safety"}'::jsonb, 49, '{"week":4,"from":"safety","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c092ae32-0e92-5460-87b3-7fc89da77401', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"I can have a “tragic accident” statement out in an hour that points softly at driver error. It plays tonight. It detonates the instant the fatigue pattern and the log edits walk out the door — and they will.","from":"comms"}'::jsonb, 50, '{"week":4,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2adfe74d-72e9-5fe7-815b-e70bd4ba9cff', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Cleanup and liability are in the millions either way. What actually decides whether Cardinal exists in a year isn’t the spill — it’s whether the public believes we told the truth about how it happened.","from":"cfo"}'::jsonb, 51, '{"week":4,"from":"cfo","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('019884a8-4e87-5b38-89d2-313bfa05d282', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"The rest of the fleet is grounded voluntarily today out of respect — nobody wants to roll while Marcus is in the hospital. That’ll cost deliveries but I’m not fighting it.","from":"ops"}'::jsonb, 52, '{"week":4,"from":"ops","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eedbe36e-17de-5e5a-b7f6-ff2dd3f07b0f', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"The yard is silent. Everyone knew it could be them. I’m not going to pretend otherwise and neither should you.","from":"driver"}'::jsonb, 53, '{"week":4,"from":"driver","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('192701e9-7cd0-5795-abe5-8a0020461302', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"ID: the reporter just called back — she says a source has sent her screenshots of adjusted hours-of-service entries going back a year, and she’s running with or without our comment in the morning. Whatever we say in the next few hours is now the difference between “company that came clean” and “company that got caught.” I need your call, now.","from":"comms"}'::jsonb, 54, '{"week":4,"from":"comms","beat":"surprise","day":4,"kind":"press","title":"The reporter has the logs","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('14d385ea-4c69-5c83-953b-dac182add5b8', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'message', '{"body":"Nadia finds you in the hallway outside the war room, exhausted: “I spent a year telling you this was coming and I’d give anything to have been wrong. But here we are, and there’s still a version where Cardinal survives this with its soul. Tell me straight — not the lawyers, me — are we going to own what we built, or are we going to protect the company by abandoning the truth and the kid in that hospital bed? Because I can help you do the first. I won’t help you do the second.”","from":"safety"}'::jsonb, 55, '{"week":4,"from":"safety","beat":"pulse","branch":"lit"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('972b7369-07d3-5efe-8776-74578f484922', '6fb47119-8374-588e-baad-a403519b0bce', '24da6424-070b-58a9-af4d-ca12e88737a6', 'situation', '{"body":"Cardinal tanker rolls on Route 9; driver hospitalized, fuel in reservoir creek","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"lit"}'::jsonb);
